(function(){
  function qs(s,c){return (c||document).querySelector(s)}
  function qsa(s,c){return Array.from((c||document).querySelectorAll(s))}
  function escHtml(str){return String(str).replace(/[&<>'"]/g,function(m){return({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'})[m];});}

  document.addEventListener('DOMContentLoaded',function(){
    var body=document.body;
    var topbarInner=qs('.topbar-inner');

    var promo=document.createElement('div');
    promo.className='promo-bar';
    promo.innerHTML='<div class="container promo-inner"><span>🔥 Haftalık Kampanya: Hızlı üretimde %10 avantaj</span><a href="teklif.html">Teklif Al</a></div>';
    body.insertBefore(promo,body.firstChild);

    var progressTrack=document.createElement('div');
    progressTrack.className='progress-track';
    progressTrack.innerHTML='<div class="progress-bar" data-read-progress></div>';
    body.appendChild(progressTrack);

    if(topbarInner){
      var controls=document.createElement('div');
      controls.className='topbar-controls';
      controls.innerHTML='<button class="icon-btn" type="button" aria-label="Tema değiştir" data-theme-toggle>◐</button>';
      topbarInner.appendChild(controls);
    }

    var scrollTopBtn=document.createElement('button');
    scrollTopBtn.className='btn btn-secondary scroll-top';
    scrollTopBtn.type='button';
    scrollTopBtn.textContent='↑ Yukarı Çık';
    body.appendChild(scrollTopBtn);

    var themeKey='minifab-theme';
    function setTheme(theme){body.classList.toggle('light-theme',theme==='light');try{localStorage.setItem(themeKey,theme);}catch(err){}}
    try{var stored=localStorage.getItem(themeKey);if(stored){setTheme(stored);}else if(window.matchMedia&&window.matchMedia('(prefers-color-scheme: light)').matches){setTheme('light');}}catch(err){}

    var themeToggle=qs('[data-theme-toggle]');
    if(themeToggle){themeToggle.addEventListener('click',function(){setTheme(body.classList.contains('light-theme')?'dark':'light');});}

    function updateScrollUi(){
      var doc=document.documentElement;
      var max=doc.scrollHeight-window.innerHeight;
      var ratio=max>0?(window.scrollY/max)*100:0;
      var bar=qs('[data-read-progress]');
      if(bar){bar.style.width=ratio+'%';}
      scrollTopBtn.classList.toggle('visible',window.scrollY>420);
    }
    window.addEventListener('scroll',updateScrollUi,{passive:true});
    window.addEventListener('resize',updateScrollUi);
    updateScrollUi();
    scrollTopBtn.addEventListener('click',function(){window.scrollTo({top:0,behavior:'smooth'});});

    var toggle=qs('.menu-toggle'),nav=qs('nav');
    if(toggle&&nav){toggle.addEventListener('click',function(){var open=nav.classList.toggle('open');toggle.setAttribute('aria-expanded',open?'true':'false');});}

    var params=new URLSearchParams(window.location.search);
    var sentBanner=qs('[data-sent-banner]');
    if(sentBanner&&params.get('sent')==='1'){sentBanner.hidden=false;}
    var modelName=params.get('model'),modelLink=params.get('link');
    var modelNameInput=qs('#modelAdi'),modelLinkInput=qs('#modelLink'),prefillBanner=qs('[data-prefill-banner]');
    if(modelName&&modelNameInput){modelNameInput.value=modelName;}
    if(modelLink&&modelLinkInput){modelLinkInput.value=modelLink;}
    if(prefillBanner&&(modelName||modelLink)){prefillBanner.hidden=false;}

    var quoteForm=qs('.quote-form');
    if(quoteForm){
      var estimateOutput=qs('[data-estimator-output]',quoteForm),quantityField=qs('#quantity',quoteForm),materialField=qs('#material',quoteForm),serviceField=qs('#serviceType',quoteForm),urgencyField=qs('#urgency',quoteForm),cityField=qs('#deliveryCity',quoteForm),deliveryOutput=qs('[data-delivery-output]',quoteForm);

      function updateEstimate(){
        if(!estimateOutput)return;
        var qty=Math.max(parseInt(quantityField&&quantityField.value||'1',10),1);
        var material=((materialField&&materialField.value)||'PLA').toUpperCase();
        var materialFactor={PLA:1,PETG:1.2,ABS:1.3,TPU:1.4,'BILMIYORUM':1.15}[material]||1;
        var service=((serviceField&&serviceField.value)||'3D Baskı');
        var serviceFactor=service.indexOf('Tasarım')>-1?1.45:service.indexOf('Kurumsal')>-1?1.6:1;
        var rushFactor=urgencyField&&urgencyField.value==='rush'?1.3:1;
        var low=Math.max(350,Math.round(220*qty*materialFactor*serviceFactor*rushFactor));
        var high=Math.round(low*1.35);
        estimateOutput.textContent='₺'+low.toLocaleString('tr-TR')+' - ₺'+high.toLocaleString('tr-TR');
      }
      function updateDelivery(){
        if(!deliveryOutput||!cityField)return;
        var city=cityField.value;
        var day=urgencyField&&urgencyField.value==='rush'?2:5;
        var transit={istanbul:1,ankara:2,izmir:2,other:3}[city]||0;
        if(!city){deliveryOutput.textContent='Şehir seçtiğinizde tahmini aralık gösterilir.';return;}
        deliveryOutput.textContent='Tahmini teslim: '+(day+transit)+' - '+(day+transit+2)+' iş günü';
      }
      [quantityField,materialField,serviceField,urgencyField].forEach(function(f){if(f){f.addEventListener('input',updateEstimate);f.addEventListener('change',updateEstimate);}});
      [urgencyField,cityField].forEach(function(f){if(f){f.addEventListener('change',updateDelivery);}});
      updateEstimate();updateDelivery();

      var autoKey=quoteForm.getAttribute('data-autosave');
      if(autoKey){
        var fields=qsa('input,select,textarea',quoteForm).filter(function(el){return el.name&&!el.type.match(/file|submit|hidden|checkbox|radio/);});
        try{var saved=localStorage.getItem(autoKey);if(saved){var data=JSON.parse(saved);fields.forEach(function(el){if(data[el.name]){el.value=data[el.name];}});}}catch(err){}
        fields.forEach(function(el){el.addEventListener('input',function(){try{var payload={};fields.forEach(function(field){payload[field.name]=field.value;});localStorage.setItem(autoKey,JSON.stringify(payload));}catch(err){}});});
        quoteForm.addEventListener('submit',function(){try{localStorage.removeItem(autoKey);}catch(err){}});
      }

      quoteForm.addEventListener('submit',function(e){
        var linkField=qs('#modelLink',quoteForm),fileField=qs('#modelFile',quoteForm);
        var hasLink=!!(linkField&&linkField.value.trim()),hasFile=!!(fileField&&fileField.files&&fileField.files.length>0);
        if(!hasLink&&!hasFile){e.preventDefault();if(linkField){linkField.setCustomValidity('Lütfen model linki ekleyin veya STL dosyası yükleyin.');linkField.reportValidity();}return;}
        if(fileField&&fileField.files&&fileField.files.length>0&&!/\.(stl|3mf|obj)$/i.test(fileField.files[0].name)){e.preventDefault();fileField.setCustomValidity('Lütfen STL, 3MF veya OBJ formatında dosya yükleyin.');fileField.reportValidity();}
      });
    }

    var products=window.MINIFAB_PRODUCTS||null,productsGrid=qs('#products-grid');
    if(products&&productsGrid){
      productsGrid.innerHTML=products.map(function(p){
        var teklif='teklif.html?model='+encodeURIComponent(p.title)+'&link='+encodeURIComponent(p.link);
        return '<article class="card product-card generated-card" data-category="'+escHtml(p.category)+'" data-title="'+escHtml(p.title)+'">'+(p.popular?'<span class="pop-badge">Popüler</span>':'')+'<a class="card-main-link" href="'+escHtml(p.link)+'" target="_blank" rel="noopener noreferrer"><img class="topic-thumb" src="'+escHtml(p.img)+'" width="700" height="420" loading="lazy" decoding="async" alt="'+escHtml(p.title)+' 3D baskı örneği" /><h2>'+escHtml(p.title)+'</h2></a><p>'+escHtml(p.description)+'</p><div class="meta-row"><span class="tag">'+escHtml(p.material)+'</span><span class="tag">'+escHtml(p.time)+'</span><span class="tag">'+escHtml(p.category)+'</span></div><a class="btn btn-secondary" href="'+escHtml(p.link)+'" target="_blank" rel="noopener noreferrer">MakerWorld\'de aç</a><a class="btn btn-primary" href="'+teklif+'">Bunu Bastır (Teklif Al)</a></article>';
      }).join('');

      function saveRecent(card){
        try{
          var payload={title:qs('h2',card).textContent.trim(),img:qs('img',card).getAttribute('src'),link:qs('.btn-primary',card).getAttribute('href')};
          var items=JSON.parse(localStorage.getItem('minifab-recent')||'[]').filter(function(x){return x.title!==payload.title;});
          items.unshift(payload);localStorage.setItem('minifab-recent',JSON.stringify(items.slice(0,4)));
        }catch(err){}
      }
      qsa('.generated-card').forEach(function(card){
        card.addEventListener('click',function(e){if(e.target.closest('a')||e.target.closest('button')) return;var main=qs('.card-main-link',card);if(main){window.open(main.href,'_blank','noopener');}});
        qsa('a',card).forEach(function(link){link.addEventListener('click',function(){saveRecent(card);});});
      });

      var recentWrap=qs('#recentlyViewed'),recentGrid=qs('[data-recent-grid]');
      if(recentWrap&&recentGrid){
        try{
          var recent=JSON.parse(localStorage.getItem('minifab-recent')||'[]');
          if(recent.length){
            recentWrap.hidden=false;
            recentGrid.innerHTML=recent.map(function(item){return '<article class="card product-card"><img class="topic-thumb" src="'+escHtml(item.img)+'" alt="'+escHtml(item.title)+'" /><h3>'+escHtml(item.title)+'</h3><a class="btn btn-primary" href="'+escHtml(item.link)+'">Tekrar Teklif Al</a></article>';}).join('');
          }
        }catch(err){}
      }
    }

    function applyCardFilters(){
      var activeBtn=qs('.filter-btn.active'),key=activeBtn?activeBtn.getAttribute('data-filter'):'all';
      qsa('[data-live-search]').forEach(function(input){
        var target=input.getAttribute('data-live-search'),term=(input.value||'').trim().toLowerCase(),visible=0;
        qsa(target).forEach(function(card){
          var cat=card.getAttribute('data-category'),show=(key==='all'||cat===key)&&((card.textContent||'').toLowerCase().indexOf(term)>-1||!term);
          card.style.display=show?'block':'none';if(show){visible++;}
        });
        var counter=qs('[data-results-count="'+target+'"]');if(counter){counter.textContent=visible+' sonuç listeleniyor.';}
      });
    }

    qsa('.filter-btn').forEach(function(btn){btn.addEventListener('click',function(){qsa('.filter-btn').forEach(function(x){x.classList.remove('active')});btn.classList.add('active');applyCardFilters();});});
    qsa('[data-live-search]').forEach(function(input){input.addEventListener('input',applyCardFilters);});
    applyCardFilters();

    if(document.body.dataset.redirectHome==='true'){setTimeout(function(){window.location.href='index.html';},2000);}
  });
})();
